const input = $input.first().json;
const userData = $('Filtrar e Extrair Dados').first().json;
let aiResponse;
try {
  let text = input.output || '{}';
  // Remove markdown code blocks (handles invisible chars, whitespace variations)
  text = text.replace(/[\s\S]*?```(?:json)?[\s\n]*/i, '');
  text = text.replace(/```[\s\S]*/g, '');
  text = text.trim();
  // If text doesn't start with {, try to find a JSON object inside
  if (!text.startsWith('{')) {
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    if (jsonMatch) text = jsonMatch[0];
  }
  aiResponse = JSON.parse(text);
} catch (e) {
  // JSON parse failed - extract fields via regex to NEVER send raw JSON
  const rawText = input.output || '';
  let extractedResponse = '';
  const respMatch = rawText.match(/"response"\s*:\s*"((?:[^"\\]|\\.)*)"/);
  if (respMatch) {
    extractedResponse = respMatch[1].replace(/\\n/g, '\n').replace(/\\"/g, '"').replace(/\\\\/g, '\\');
  }
  let extractedIntent = 'CONVERSA_GERAL';
  const intMatch = rawText.match(/"intent"\s*:\s*"([^"]+)"/);
  if (intMatch) extractedIntent = intMatch[1];
  let extractedStage = 'greeting';
  const stgMatch = rawText.match(/"stage"\s*:\s*"([^"]+)"/);
  if (stgMatch) extractedStage = stgMatch[1];
  let extractedCourse = '';
  const crsMatch = rawText.match(/"courseQuery"\s*:\s*"([^"]*)"/); 
  if (crsMatch) extractedCourse = crsMatch[1];
  let extractedCity = '';
  const cityMatch = rawText.match(/"city"\s*:\s*"([^"]*)"/); 
  if (cityMatch) extractedCity = cityMatch[1];
  aiResponse = {
    intent: extractedIntent,
    response: extractedResponse || 'Desculpe, tive um probleminha. Pode repetir? 😊',
    stage: extractedStage,
    courseQuery: extractedCourse,
    city: extractedCity,
    leadData: {}
  };
}
const leadData = aiResponse.leadData || {};
Object.keys(leadData).forEach(key => { if (!leadData[key] || leadData[key] === 'null' || leadData[key] === 'undefined') delete leadData[key]; });
return [{ json: { phone: userData.phone, remoteJid: userData.remoteJid, text: userData.text, pushName: userData.pushName, timestamp: userData.timestamp, userName: userData.pushName || '', intent: aiResponse.intent || 'CONVERSA_GERAL', response: aiResponse.response || 'Como posso te ajudar? 😊', courseQuery: aiResponse.courseQuery || '', academicLevel: aiResponse.academicLevel || 'GRADUACAO', modality: aiResponse.modality || 'EAD', city: aiResponse.city || '', leadData, stage: aiResponse.stage || 'greeting' } }];

const data = $input.first().json;
const intent = data.intent || 'CONVERSA_GERAL';
const item = [{ json: data }];
const empty = [];
// Outputs: 0=BUSCAR_CURSO, 1=DETALHE_CURSO, 2=INFO_ACADEMICA, 3=CAPTURAR_LEAD, 4=TRANSFERIR_HUMANO, 5=FALLBACK
const outputs = [empty, empty, empty, empty, empty, empty];
switch (intent) {
  case 'BUSCAR_CURSO': outputs[0] = item; break;
  case 'DETALHE_CURSO': outputs[1] = item; break;
  case 'INFO_ACADEMICA': outputs[2] = item; break;
  case 'CAPTURAR_LEAD': outputs[3] = item; break;
  case 'TRANSFERIR_HUMANO': outputs[4] = item; break;
  default: outputs[5] = item; break;
}
return outputs;

const coursesResponse = $input.first().json;
const prevData = $('Parsear Resposta Gemini').first().json;
const courses = coursesResponse.content || coursesResponse.data || coursesResponse || [];
const courseList = Array.isArray(courses) ? courses : [];
let finalResponse = prevData.response;
if (courseList.length > 0) {
  // Deduplica por brand+preco para nao mostrar cursos identicos
  const seen = new Set();
  const unique = courseList.filter(c => {
    const brand = c.brand?.name || c.brandName || c.institution || c.unit?.name || '';
    const price = c.minPrice || c.priceWithDiscount || 0;
    const key = `${brand}-${price}`;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  }).slice(0, 5);
  const list = unique.map((c, i) => {
    const name = c.name || c.courseName || 'Curso';
    const brand = c.brand?.name || c.brandName || c.institution || c.unit?.name || '';
    const modality = c.modality || prevData.modality || 'EAD';
    const city = c.city || c.unit?.city || prevData.city || '';
    const rawDuration = c.duration || c.semesters || c.workload || '';
    let duration = '';
    if (rawDuration) {
      const num = Number(rawDuration);
      if (num > 0 && num <= 12) duration = `${num} semestres (${num * 6} meses)`;
      else if (num > 12) duration = `${num} meses`;
      else duration = String(rawDuration);
    }
    const minPrice = c.minPrice || c.priceWithDiscount || c.installmentValue;
    const maxPrice = c.maxPrice || c.originalPrice || c.fullPrice;
    const discount = (minPrice && maxPrice && maxPrice > 0) ? Math.round((1 - minPrice / maxPrice) * 100) : null;
    const tipo = c.type || c.courseType || '';
    const tipoLabel = tipo === 'BACHARELADO' ? 'Bacharelado' : tipo === 'LICENCIATURA' ? 'Licenciatura' : tipo === 'TECNOLOGO' ? 'Tecnologo' : '';
    let line = `*${i + 1}. ${name}*`;
    if (brand || city) line += `\n   🏫 ${brand}${city ? (brand ? ' - ' : '') + city : ''}`;
    if (tipoLabel) line += `\n   📚 ${tipoLabel} | ${modality}`;
    else line += `\n   📚 ${modality}`;
    if (minPrice && maxPrice && discount && discount > 0) {
      line += `\n   💰 De ~R$${Number(maxPrice).toFixed(2)}~ por *R$${Number(minPrice).toFixed(2)}/mes* (${discount}% OFF)`;
    } else if (minPrice) {
      line += `\n   💰 *R$${Number(minPrice).toFixed(2)}/mes*`;
    }
    if (duration) line += `\n   ⏱ ${duration}`;
    const slug = name.normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
    line += `\n   🔗 https://www.bolsaclick.com.br/cursos/${slug}`;
    return line;
  }).join('\n\n');
  finalResponse += '\n\n' + list + '\n\nQual dessas opcoes te interessou? Me diz o numero que te passo mais detalhes! 😉';
} else if (prevData.courseQuery) {
  finalResponse += '\n\nNao encontrei esse curso no momento. Tenta me dizer de outra forma ou me conta a area que te interessa!';
}
return [{ json: { ...prevData, response: finalResponse } }];

const searchResult = $input.first().json;
const prevData = $('Parsear Resposta Gemini').first().json;
const courses = searchResult.content || searchResult.data || searchResult || [];
const courseList = Array.isArray(courses) ? courses : [];
if (courseList.length === 0) {
  return [{ json: { ...prevData, response: prevData.response + '\n\nNao encontrei detalhes para esse curso. Pode me dizer o nome completo? 😊', skipDetail: true } }];
}
const course = courseList[0];
return [{ json: { ...prevData, detailCourse: course, businessKey: course.businessKey || course.groupId || course.id || '', unitId: course.unitId || course.unit?.id || '', detailModality: course.modality || prevData.modality || 'EAD', detailShift: course.shift || 'VIRTUAL', skipDetail: false } }];

const details = $input.first().json;
const prevData = $('Extrair Dados para Detalhe').first().json;
if (prevData.skipDetail) {
  return [{ json: { ...prevData } }];
}
const course = prevData.detailCourse || {};
const name = course.name || course.courseName || prevData.courseQuery || 'Curso';
const brand = course.brand?.name || course.brandName || course.institution || course.unit?.name || '';
const modality = course.modality || prevData.modality || 'EAD';
const level = course.academicLevel || course.level || 'Graduacao';
const duration = course.duration || (course.semesters ? (course.semesters * 6) + ' meses' : '');
const offer = details.offer || details.data || details || {};
const minPrice = offer.minPrice || offer.priceWithDiscount || offer.installmentValue || course.minPrice;
const maxPrice = offer.maxPrice || offer.originalPrice || offer.fullPrice || course.maxPrice;
const discount = (minPrice && maxPrice && maxPrice > 0) ? Math.round((1 - minPrice / maxPrice) * 100) : null;
const installments = offer.installments || offer.parcelas || [];
const shift = offer.shift || course.shift || 'Virtual';
let msg = `📋 *Detalhes: ${name}*\n`;
msg += `🏫 ${brand}\n`;
msg += `📚 ${level} | ${modality}\n`;
if (shift) msg += `🕐 Turno: ${shift}\n`;
if (duration) msg += `⏱ Duracao: ${duration}\n`;
msg += '\n';
if (minPrice && maxPrice && discount) {
  msg += `💰 *Valor com bolsa:*\n`;
  msg += `   De ~R$${Number(maxPrice).toFixed(2)}~ por *R$${Number(minPrice).toFixed(2)}/mes*\n`;
  msg += `   🎉 *${discount}% de desconto!*\n`;
} else if (minPrice) {
  msg += `💰 *Valor: R$${Number(minPrice).toFixed(2)}/mes*\n`;
}
if (Array.isArray(installments) && installments.length > 0) {
  msg += '\n📊 *Opcoes de parcelas:*\n';
  installments.slice(0, 3).forEach(inst => {
    const qty = inst.quantity || inst.installments || inst.parcelas;
    const value = inst.value || inst.amount || inst.valor;
    if (qty && value) msg += `   • ${qty}x de R$${Number(value).toFixed(2)}\n`;
  });
}
const slug = name.normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
msg += `\n👉 *Garanta sua bolsa:*\nhttps://www.bolsaclick.com.br/cursos/${slug}\n`;
msg += '\nQuer se matricular ou tem alguma duvida? 😊';
return [{ json: { ...prevData, response: msg } }];

const input = $input.first().json;
const prevData = $('Parsear Resposta Gemini').first().json;
const academicInfo = input.output || '';
let finalResponse = prevData.response;
if (academicInfo) { finalResponse = academicInfo + '\n\n💰 Quer saber os valores com bolsa no Bolsa Click? Me diga a cidade e modalidade de interesse!'; }
return [{ json: { ...prevData, response: finalResponse } }];

const leadResult = $input.first().json;
const prevData = $('Parsear Resposta Gemini').first().json;
let finalResponse = prevData.response;
if (leadResult.lead?.id) { prevData.leadData.leadId = leadResult.lead.id; }
return [{ json: { ...prevData, response: finalResponse } }];

const prevData = $('Parsear Resposta Gemini').first().json;
let response = prevData.response;
if (prevData.intent === 'CHECKOUT' && prevData.leadData?.courseInterest) {
  const slug = prevData.leadData.courseInterest.normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
  if (!response.includes('bolsaclick.com.br')) { response += '\n\n👉 https://www.bolsaclick.com.br/cursos/' + slug; }
}
return [{ json: { ...prevData, response } }];

const data = $input.first().json;
let response = (data.response || 'Como posso te ajudar? 😊').substring(0, 4000);
return [{ json: { phone: data.phone, remoteJid: data.remoteJid, text: data.text, pushName: data.pushName, userName: data.userName, timestamp: data.timestamp, response, intent: data.intent, stage: data.stage, leadData: data.leadData || {} } }];
